import * as Y from "yjs";
import { StateCreator } from "zustand";

//#region src/y-zustand.d.ts
interface SyncYjsOptions<T> {
  /**
   * A function that takes the current state and returns a new state object
   * with only the fields that should be synced with Yjs.
   * By default, all fields are synced.
   */
  partialize?: (state: T) => Partial<T>;
}
declare const syncYjsMiddleware: <T extends object>(doc: Y.Doc, name: string, options?: SyncYjsOptions<T>) => (creator: StateCreator<T>) => StateCreator<T>;
//#endregion
export { SyncYjsOptions, syncYjsMiddleware };